from fastapi import FastAPI, Request, Form, status
from fastapi.templating import Jinja2Templates
from fastapi.responses import RedirectResponse

# Initialize the FastAPI application
app = FastAPI(
    title="Cyberpunk Login",
    description="A basic FastAPI application for a cyberpunk-themed login page.",
    version="0.1.0"
)

# Configure Jinja2 templates
templates = Jinja2Templates(directory="templates")

# Dummy credentials for authentication
DUMMY_USERNAME = "user"
DUMMY_PASSWORD = "password"

@app.get("/", response_class=RedirectResponse, include_in_schema=False)
async def get_root():
    """Redirects from root to the login page."""
    return RedirectResponse(url="/login", status_code=status.HTTP_302_FOUND)

@app.get("/login", summary="Display Login Page")
async def login_page(request: Request, message: str = None, error: str = None):
    """Renders the index.html template for the login page."""
    return templates.TemplateResponse(
        "index.html", 
        {"request": request, "message": message, "error": error}
    )

@app.post("/login", summary="Handle Login Form Submission")
async def login_submit(
    request: Request,
    username: str = Form(..., description="Username for login"),
    password: str = Form(..., description="Password for login")
):
    """Handles the POST request for login form submission and performs a dummy authentication check."""
    if username == DUMMY_USERNAME and password == DUMMY_PASSWORD:
        # In a real application, you would set a session cookie or a JWT here.
        # For this example, we'll re-render the page with a success message.
        return templates.TemplateResponse(
            "index.html", 
            {"request": request, "message": f"Welcome, {username}! Access Granted."}
        )
    else:
        # Re-render the login page with an error message
        return templates.TemplateResponse(
            "index.html", 
            {"request": request, "error": "Invalid credentials. Try 'user' and 'password'."}
        )
